Here is a C++ program that reads a text file line by line and counts the number of occurrences of a specific word in the file:
```c++
#include <iostream>
#include <string>
#include <vector>
#include <unordered_map>

int main() {
    std::string word_to_count;
    std::cin >> word_to_count;

    std::ifstream input_file("input.txt");
    if (!input_file) {
        std::cerr << "Error opening file." << std::endl;
        return 1;
    }

    std::string line;
    std::unordered_map<std::string, int> word_counts;

    while (std::getline(input_file, line)) {
        for (std::string word : line.split(' ')) {
            if (word == word_to_count) {
                ++word_counts[word];
            } else {
                word_counts[word]++;
            }
        }
    }

    input_file.close();

    for (const auto& pair : word_counts) {
        std::cout << pair.first << ": " << pair.second << " occurrences\n";
    }

    return 0;
}
```
